// ─── Main Import Function ────────────────────────────────────────────────────

async function importFormulary() {
  const client = new MongoClient(MONGO_URI);

  try {
    await client.connect();
    console.log('Connected to MongoDB\n');

    const db = client.db(DB_NAME);
    const col = db.collection(COLLECTION);

    // Drop existing collection
    try { await col.drop(); } catch (e) { /* collection may not exist */ }
    console.log(`Dropped existing ${COLLECTION} collection (if any)`);

    // Add metadata to each drug
    const now = new Date();
    const enrichedDrugs = drugs.map(drug => ({
      ...drug,
      priorAuthReason: drug.priorAuthReason || '',
      controlledSchedule: drug.controlledSchedule || '',
      lastUpdated: now,
      source: 'Medicare Part D Standard Benefit Design (2026)',
      // Normalize drugName for search
      drugNameLower: drug.drugName.toLowerCase(),
      brandNamesLower: drug.brandNames.map(b => b.toLowerCase())
    }));

    // Insert all drugs
    const result = await col.insertMany(enrichedDrugs);
    console.log(`Inserted ${result.insertedCount} drugs into ${COLLECTION}`);

    // Create indexes
    console.log('\nCreating indexes...');
    await col.createIndex({ drugNameLower: 1 }, { name: 'idx_drugName' });
    await col.createIndex({ brandNamesLower: 1 }, { name: 'idx_brandNames' });
    await col.createIndex({ tier: 1 }, { name: 'idx_tier' });
    await col.createIndex({ drugClass: 1 }, { name: 'idx_drugClass' });
    await col.createIndex({ category: 1 }, { name: 'idx_category' });
    await col.createIndex(
      { drugName: 'text', brandNames: 'text', drugClass: 'text', commonIndications: 'text' },
      { name: 'idx_text_search', weights: { drugName: 10, brandNames: 8, drugClass: 3, commonIndications: 2 } }
    );
    console.log('Indexes created');

    // Print summary
    const categories = await col.aggregate([
      { $group: { _id: '$category', count: { $sum: 1 } } },
      { $sort: { count: -1 } }
    ]).toArray();

    console.log('\n=== IMPORT SUMMARY ===');
    console.log(`Total drugs: ${result.insertedCount}`);
    console.log(`Database: ${DB_NAME}`);
    console.log(`Collection: ${COLLECTION}`);
    console.log('\nBy category:');
    categories.forEach(c => console.log(`  ${c._id}: ${c.count}`));

    const tierCounts = await col.aggregate([
      { $group: { _id: '$tier', count: { $sum: 1 } } },
      { $sort: { _id: 1 } }
    ]).toArray();
    console.log('\nBy tier:');
    tierCounts.forEach(t => {
      const names = { 1: 'Preferred Generic', 2: 'Generic', 3: 'Preferred Brand', 4: 'Non-Preferred Brand', 5: 'Specialty' };
      console.log(`  Tier ${t._id} (${names[t._id]}): ${t.count}`);
    });

    console.log('\n=== IMPORT COMPLETE ===');

  } catch (error) {
    console.error('Import failed:', error);
    process.exit(1);
  } finally {
    await client.close();
  }
}

importFormulary();
